1	//! `panopt up` - boot or attach the cockpit.
2	
3	use std::os::unix::process::CommandExt;
4	use std::path::{Path, PathBuf};
5	use std::process::Command;
6	
7	use anyhow::{bail, Context, Result};
8	
9	use crate::{daemon, mcp, paths};
10	
11	/// The cockpit layout: five fixed plugin panes stacked vertically on the
12	/// left (one per resource kind) and a single content pane on the right.
13	///
14	/// Each plugin pane is one Zellij plugin instance running the same wasm
15	/// binary, configured by a distinct `mode` value (`todos`, `agents`,
16	/// `terminals`, `commands`, `scratchpads`). Zellij keys plugin identity on
17	/// `(URL, configuration)`, so the five panes are five distinct instances.
18	/// Layout-pinned in the `ui` tab template, so adding or removing panes on
19	/// the right cannot reshape them.
20	///
21	/// The content pane starts as one empty `panopt _viewer`; selections in any
22	/// of the five panes swap their target into that one slot, suppressing
23	/// whatever was there. The user is free to split the content pane to make
24	/// further slots.
25	///
26	/// `{{PROJECT}}`, `{{WASM}}`, `{{PANOPT_BIN}}`, and `{{PORT}}` are
27	/// substituted by [`render_layout`]; each may appear more than once.
28	const LAYOUT_TEMPLATE: &str = r#"// PANopt cockpit - generated by `panopt up`. Regenerated on each run.
29	// Five plugin panes stack vertically on the LEFT (~25% column), one per
30	// resource kind; a single content pane sits on the RIGHT. Selections swap
31	// into that one pane - suppressed panes keep running, hidden.
32	layout {
33	    cwd "{{PROJECT}}"
34	
35	    // The fixed shell of every tab: five plugin panes pinned left (one per
36	    // mode), the content pane on the right flows into the `children` slot.
37	    tab_template name="ui" {
38	        pane split_direction="vertical" {
39	            pane size="25%" split_direction="horizontal" {
40	                pane size="30%" {
41	                    plugin location="file:{{WASM}}" {
42	                        mode "todos"
43	                        ws "{{PROJECT}}"
44	                        panopt_bin "{{PANOPT_BIN}}"
45	                        port "{{PORT}}"
46	                    }
47	                }
48	                pane size="15%" {
49	                    plugin location="file:{{WASM}}" {
50	                        mode "agents"
51	                        ws "{{PROJECT}}"
52	                        panopt_bin "{{PANOPT_BIN}}"
53	                        port "{{PORT}}"
54	                    }
55	                }
56	                pane size="15%" {
57	                    plugin location="file:{{WASM}}" {
58	                        mode "terminals"
59	                        ws "{{PROJECT}}"
60	                        panopt_bin "{{PANOPT_BIN}}"
61	                        port "{{PORT}}"
62	                    }
63	                }
64	                pane size="15%" {
65	                    plugin location="file:{{WASM}}" {
66	                        mode "commands"
67	                        ws "{{PROJECT}}"
68	                        panopt_bin "{{PANOPT_BIN}}"
69	                        port "{{PORT}}"
70	                    }
71	                }
72	                pane size="25%" {
73	                    plugin location="file:{{WASM}}" {
74	                        mode "scratchpads"
75	                        ws "{{PROJECT}}"
76	                        panopt_bin "{{PANOPT_BIN}}"
77	                        port "{{PORT}}"
78	                    }
79	                }
80	            }
81	            pane {
82	                children
83	            }
84	        }
85	    }
86	
87	    // Initial state: the five plugin panes plus one empty document viewer.
88	    ui {
89	        pane command="{{PANOPT_BIN}}" {
90	            args "_viewer" "--slot" "main" "--port" "{{PORT}}"
91	        }
92	    }
93	}
94	"#;
95	
96	/// Zellij's stock keybinding that enters scroll mode, and the cockpit's
97	/// replacement. [`render_config`] rewrites the first to the second so a bare
98	/// Ctrl-S is left unbound and reaches the focused pane - the todo form
99	/// (`panopt todo edit`) saves on it. Scroll mode moves to Ctrl-Shift-S.
100	///
101	/// Zellij layouts cannot carry keybindings (`keybinds` is not a layout node),
102	/// so this is applied to a generated config handed to Zellij via `--config`.
103	const SCROLL_BIND_FROM: &str = r#"bind "Ctrl s" { SwitchToMode "scroll"; }"#;
104	const SCROLL_BIND_TO: &str = r#"bind "Ctrl Shift s" { SwitchToMode "scroll"; }"#;
105	
106	/// Zellij's stock Alt-N binding opens a shell pane. The cockpit retargets it
107	/// to send the `panopt:spawn-blank-pane` pipe to the Todos plugin pane,
108	/// which (as cockpit gatekeeper) spawns a fresh empty-viewer pane with its
109	/// own routing slot - so any of the five plugin panes can later re-point it
110	/// on a selection.
111	///
112	/// Why `Run "zellij" "action" "pipe" ...` instead of `MessagePlugin`: Zellij's
113	/// KDL parser folds `MessagePlugin`'s metadata fields (`name`, `payload`,
114	/// `cwd`, `launch_new`, ...) into the plugin's user-configuration map. The
115	/// runtime then keys plugin identity on `(URL, configuration)`, so a
116	/// `MessagePlugin` keybind whose configuration has any of those metadata
117	/// keys can never match a layout plugin whose configuration does not - Zellij
118	/// launches a *second* plugin instance instead. `zellij action pipe` goes
119	/// through the running session's IPC bus and reaches the existing plugin
120	/// without that mismatch. The cost is a brief transient pane while the CLI
121	/// runs; `close_on_exit true` closes it the moment the pipe is sent.
122	///
123	/// Why `--plugin-configuration "mode=todos"`: with five plugin instances
124	/// (one per mode), an unfiltered pipe broadcasts to all five. Narrowing to
125	/// `mode=todos` delivers the message only to the gatekeeper. The plugin
126	/// also early-returns from `pipe()` on non-Todos panes - belt-and-braces if
127	/// the filter ever fails to match.
128	const NEW_PANE_BIND_FROM: &str = r#"bind "Alt n" { NewPane; }"#;
129	const NEW_PANE_BIND_TO: &str = r#"bind "Alt n" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }"#;
130	
131	/// Zellij's stock close/quit keybinds, rewritten to pipe a request to the
132	/// Todos plugin pane (cockpit gatekeeper) instead of acting immediately.
133	/// The plugin refuses the action when an active item would be lost and
134	/// otherwise force-closes through the plugin API. The `pipe` mechanism is
135	/// the same as Alt-N's rewrite - see [`NEW_PANE_BIND_FROM`] for why it goes
136	/// through `zellij action pipe` rather than `MessagePlugin`, and for the
137	/// `--plugin-configuration "mode=todos"` narrowing.
138	///
139	/// The defaults dump these in pane mode, tab mode, search mode (`x` =
140	/// CloseFocus), and a shared_except locked block (`Ctrl q` = Quit). Each FROM
141	/// here is the exact text the dump emits; [`str::replace`] catches every
142	/// occurrence so all modes funnel through the same pipe.
143	const CLOSE_FOCUS_BIND_FROM: &str = r#"bind "x" { CloseFocus; SwitchToMode "Normal"; }"#;
144	const CLOSE_FOCUS_BIND_TO: &str = r#"bind "x" { Run "zellij" "action" "pipe" "--name" "panopt:close-focus-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#;
145	const CLOSE_TAB_BIND_FROM: &str = r#"bind "x" { CloseTab; SwitchToMode "Normal"; }"#;
146	const CLOSE_TAB_BIND_TO: &str = r#"bind "x" { Run "zellij" "action" "pipe" "--name" "panopt:close-tab-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#;
147	const QUIT_BIND_FROM: &str = r#"bind "Ctrl q" { Quit; }"#;
148	const QUIT_BIND_TO: &str = r#"bind "Ctrl q" { Run "zellij" "action" "pipe" "--name" "panopt:quit-request" "--plugin-configuration" "mode=todos" { close_on_exit true; }; }"#;
149	
150	/// `panopt up` - ensure the daemon, then create or attach this project's
151	/// cockpit Zellij session.
152	///
153	/// `host`, when supplied, is forwarded to `panoptd --host` so the daemon
154	/// binds to a non-loopback interface (`0.0.0.0` to accept connections from
155	/// other machines). Ignored if the daemon is already running - the bind
156	/// address only matters when this call starts a fresh `panoptd`.
157	pub fn run(plugin: Option<PathBuf>, host: Option<String>, port: u16) -> Result<()> {
158	    if std::env::var_os("ZELLIJ").is_some() {
159	        bail!("run `panopt up` from a plain shell, not inside Zellij");
160	    }
161	
162	    daemon::ensure(host.as_deref(), port)?;
163	    mcp::ensure()?;
164	
165	    let project = std::env::current_dir().context("reading the current directory")?;
166	    let project = std::fs::canonicalize(&project)
167	        .with_context(|| format!("no such directory: {}", project.display()))?;
168	    let session = session_name(&project);
169	
170	    match session_state(&session) {
171	        SessionState::Live => {
172	            println!("attaching to cockpit `{session}`");
173	            let err = Command::new("zellij").arg("attach").arg(&session).exec();
174	            return Err(err).context("could not exec `zellij attach`");
175	        }
176	        SessionState::Dead => {
177	            // Quitting a cockpit leaves a dead, resurrectable Zellij session;
178	            // clear it so `panopt up` boots a fresh one. Daemon state (todos,
179	            // scratchpads) lives in SQLite and is unaffected.
180	            println!("clearing the dead cockpit `{session}`");
181	            let cleared = Command::new("zellij")
182	                .arg("delete-session")
183	                .arg(&session)
184	                .status()
185	                .context("running `zellij delete-session`")?;
186	            if !cleared.success() {
187	                bail!(
188	                    "could not clear the dead session `{session}`; \
189	                     remove it with `zellij delete-session {session}`"
190	                );
191	            }
192	        }
193	        SessionState::Absent => {}
194	    }
195	
196	    let wasm = match plugin {
197	        Some(p) => p,
198	        None => default_plugin_wasm()
199	            .context("could not find the panopt-zellij plugin .wasm; pass --plugin <path>")?,
200	    };
201	    let layout = render_layout(&project, &wasm, port)?;
202	    let config = match render_config() {
203	        Ok(path) => Some(path),
204	        Err(e) => {
205	            eprintln!(
206	                "warning: could not prepare the cockpit's Zellij config ({e:#}); \
207	                 starting with your default keybindings - Ctrl-S in the todo form \
208	                 may be swallowed by Zellij, and Alt-N opens a shell instead of a \
209	                 blank viewer pane"
210	            );
211	            None
212	        }
213	    };
214	    println!("starting cockpit `{session}`");
215	    // `--new-session-with-layout` always creates a fresh session; plain
216	    // `--layout` alongside `--session` would instead try to add tabs to an
217	    // existing session of that name. `--config` points Zellij at the generated
218	    // cockpit config, which frees Ctrl-S for panes so the todo form saves on it.
219	    let mut zellij = Command::new("zellij");
220	    zellij.arg("--session").arg(&session);
221	    if let Some(config) = &config {
222	        zellij.arg("--config").arg(config);
223	    }
224	    zellij.arg("--new-session-with-layout").arg(&layout);
225	    let err = zellij.exec();
226	    Err(err).context("could not exec `zellij`")
227	}
228	
229	/// The cockpit session name for a project: `panopt-<basename>-<hash>`. The
230	/// basename is reduced to characters Zellij accepts; the hash is a short
231	/// fingerprint of the canonical project path, so two projects sharing a
232	/// basename (`~/a/frontend`, `~/b/frontend`) land on distinct sessions
233	/// instead of one silently attaching to the other's cockpit.
234	fn session_name(project: &Path) -> String {
235	    let base = project
236	        .file_name()
237	        .and_then(|n| n.to_str())
238	        .unwrap_or("project");
239	    let safe: String = base
240	        .chars()
241	        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
242	        .collect();
243	    let hash = short_path_hash(project);
244	    format!("panopt-{safe}-{hash}")
245	}
246	
247	/// Stable 7-hex-char fingerprint of the canonical project path. Used as the
248	/// disambiguating suffix on the cockpit session name; see [`session_name`].
249	fn short_path_hash(project: &Path) -> String {
250	    use std::hash::{Hash, Hasher};
251	    let mut hasher = std::collections::hash_map::DefaultHasher::new();
252	    project.hash(&mut hasher);
253	    let h = hasher.finish();
254	    format!("{h:016x}").chars().take(7).collect()
255	}
256	
257	/// Whether a Zellij session named `name` exists, and if so whether it is live
258	/// or dead (exited but still resurrectable).
259	enum SessionState {
260	    Absent,
261	    Live,
262	    Dead,
263	}
264	
265	fn session_state(name: &str) -> SessionState {
266	    let Ok(out) = Command::new("zellij").arg("list-sessions").output() else {
267	        return SessionState::Absent;
268	    };
269	    let text = strip_ansi(&String::from_utf8_lossy(&out.stdout));
270	    for line in text.lines() {
271	        if line.split_whitespace().next() == Some(name) {
272	            return if line.contains("EXITED") {
273	                SessionState::Dead
274	            } else {
275	                SessionState::Live
276	            };
277	        }
278	    }
279	    SessionState::Absent
280	}
281	
282	/// Drop ANSI escape sequences so `zellij list-sessions` output can be parsed.
283	fn strip_ansi(s: &str) -> String {
284	    let mut out = String::with_capacity(s.len());
285	    let mut chars = s.chars();
286	    while let Some(c) = chars.next() {
287	        if c == '\u{1b}' {
288	            // Skip a CSI sequence up to and including its final letter.
289	            for n in chars.by_ref() {
290	                if n.is_ascii_alphabetic() {
291	                    break;
292	                }
293	            }
294	        } else {
295	            out.push(c);
296	        }
297	    }
298	    out
299	}
300	
301	/// Locate the plugin `.wasm` from a dev build, relative to this binary
302	/// (`<repo>/target/<profile>/panopt`).
303	fn default_plugin_wasm() -> Option<PathBuf> {
304	    let exe = std::env::current_exe().ok()?;
305	    let repo = exe.ancestors().nth(3)?;
306	    let wasm = repo.join("crates/panopt-zellij/target/wasm32-wasip1/release/panopt-zellij.wasm");
307	    wasm.is_file().then_some(wasm)
308	}
309	
310	/// Render the cockpit layout for `project`, write it to disk, return its path.
311	fn render_layout(project: &Path, wasm: &Path, port: u16) -> Result<PathBuf> {
312	    let panopt_bin = std::env::current_exe().context("locating the panopt binary")?;
313	    let body = LAYOUT_TEMPLATE
314	        .replace("{{PROJECT}}", &project.to_string_lossy())
315	        .replace("{{WASM}}", &wasm.to_string_lossy())
316	        .replace("{{PANOPT_BIN}}", &panopt_bin.to_string_lossy())
317	        .replace("{{PORT}}", &port.to_string());
318	    let path = paths::cockpit_layout()?;
319	    std::fs::write(&path, body).with_context(|| format!("writing {}", path.display()))?;
320	    Ok(path)
321	}
322	
323	/// Free Ctrl-S for panes by retargeting Zellij's scroll-mode keybinding to
324	/// Ctrl-Shift-S. Returns the rewritten config and whether the binding was
325	/// actually found - a reformatted or unusually customized config may not carry
326	/// it in the expected form.
327	fn retarget_scroll_binding(base: &str) -> (String, bool) {
328	    let tweaked = base.replace(SCROLL_BIND_FROM, SCROLL_BIND_TO);
329	    let changed = tweaked != base;
330	    (tweaked, changed)
331	}
332	
333	/// Retarget Zellij's Alt-N keybinding to `Run` of `zellij action pipe`, which
334	/// pipes a message to the sidebar plugin telling it to spawn a blank viewer
335	/// pane.
336	fn retarget_new_pane_binding(base: &str) -> (String, bool) {
337	    let tweaked = base.replace(NEW_PANE_BIND_FROM, NEW_PANE_BIND_TO);
338	    let changed = tweaked != base;
339	    (tweaked, changed)
340	}
341	
342	/// Retarget every CloseFocus/CloseTab/Quit keybind to `Run` of
343	/// `zellij action pipe`, sending the request to the sidebar plugin instead of
344	/// acting immediately. The plugin gates these against active items and either
345	/// refuses (showing a floating dialog) or force-closes via the plugin API,
346	/// which bypasses the rewritten keybinds.
347	///
348	/// The returned tuple reports whether each rewrite was found - users with a
349	/// reformatted or heavily-customized config may have moved them; we warn so
350	/// the user knows the gate has gaps. The default Zellij dump emits the
351	/// CloseFocus binding in multiple modes; `str::replace` catches every copy.
352	fn retarget_close_bindings(base: &str) -> (String, bool, bool, bool) {
353	    let after_close_focus = base.replace(CLOSE_FOCUS_BIND_FROM, CLOSE_FOCUS_BIND_TO);
354	    let close_focus_changed = after_close_focus != base;
355	    let after_close_tab = after_close_focus.replace(CLOSE_TAB_BIND_FROM, CLOSE_TAB_BIND_TO);
356	    let close_tab_changed = after_close_tab != after_close_focus;
357	    let after_quit = after_close_tab.replace(QUIT_BIND_FROM, QUIT_BIND_TO);
358	    let quit_changed = after_quit != after_close_tab;
359	    (
360	        after_quit,
361	        close_focus_changed,
362	        close_tab_changed,
363	        quit_changed,
364	    )
365	}
366	
367	/// Locate the Zellij config file Zellij itself would load, following its own
368	/// lookup order: `$ZELLIJ_CONFIG_FILE`, `$ZELLIJ_CONFIG_DIR/config.kdl`,
369	/// `$XDG_CONFIG_HOME/zellij/config.kdl`, then `~/.config/zellij/config.kdl`.
370	/// `None` when the user keeps no config and relies on Zellij's defaults.
371	fn user_zellij_config() -> Option<PathBuf> {
372	    if let Some(file) = std::env::var_os("ZELLIJ_CONFIG_FILE") {
373	        let path = PathBuf::from(file);
374	        if path.is_file() {
375	            return Some(path);
376	        }
377	    }
378	    let config_kdl = |dir: PathBuf| {
379	        let path = dir.join("config.kdl");
380	        path.is_file().then_some(path)
381	    };
382	    if let Some(dir) = std::env::var_os("ZELLIJ_CONFIG_DIR") {
383	        if let Some(path) = config_kdl(PathBuf::from(dir)) {
384	            return Some(path);
385	        }
386	    }
387	    if let Some(dir) = std::env::var_os("XDG_CONFIG_HOME") {
388	        if let Some(path) = config_kdl(PathBuf::from(dir).join("zellij")) {
389	            return Some(path);
390	        }
391	    }
392	    dirs::home_dir().and_then(|home| config_kdl(home.join(".config").join("zellij")))
393	}
394	
395	/// The Zellij config to derive the cockpit's from: the user's own config, or -
396	/// when they keep none - Zellij's built-in defaults via `zellij setup
397	/// --dump-config`.
398	fn base_zellij_config() -> Result<String> {
399	    if let Some(path) = user_zellij_config() {
400	        return std::fs::read_to_string(&path)
401	            .with_context(|| format!("reading the Zellij config {}", path.display()));
402	    }
403	    let out = Command::new("zellij")
404	        .args(["setup", "--dump-config"])
405	        .output()
406	        .context("running `zellij setup --dump-config`")?;
407	    if !out.status.success() {
408	        bail!("`zellij setup --dump-config` exited with a failure");
409	    }
410	    String::from_utf8(out.stdout).context("`zellij setup --dump-config` produced invalid UTF-8")
411	}
412	
413	/// Generate the cockpit's Zellij config - the user's config with Ctrl-S freed
414	/// for panes so the todo form's save keybinding reaches it, and Alt-N
415	/// retargeted to spawn a blank viewer pane via the sidebar plugin - write it
416	/// to disk, and return its path. Regenerated on each run, so it tracks the
417	/// user's own config.
418	fn render_config() -> Result<PathBuf> {
419	    let base = base_zellij_config()?;
420	    let (tweaked, scroll_changed) = retarget_scroll_binding(&base);
421	    if !scroll_changed {
422	        eprintln!(
423	            "warning: Zellij's `Ctrl s` scroll binding was not found in the \
424	             expected form, so it could not be remapped; Ctrl-S in the todo \
425	             form may be swallowed by Zellij"
426	        );
427	    }
428	    let (tweaked, new_pane_changed) = retarget_new_pane_binding(&tweaked);
429	    if !new_pane_changed {
430	        eprintln!(
431	            "warning: Zellij's `Alt n` `NewPane` binding was not found in the \
432	             expected form, so it could not be remapped; Alt-N will open a \
433	             shell rather than a blank viewer pane"
434	        );
435	    }
436	    let (tweaked, close_focus_changed, close_tab_changed, quit_changed) =
437	        retarget_close_bindings(&tweaked);
438	    if !close_focus_changed {
439	        eprintln!(
440	            "warning: Zellij's `CloseFocus` binding was not found in the \
441	             expected form, so it could not be gated; closing a pane will \
442	             bypass the active-item guard"
443	        );
444	    }
445	    if !close_tab_changed {
446	        eprintln!(
447	            "warning: Zellij's `CloseTab` binding was not found in the \
448	             expected form, so it could not be gated; closing a tab will \
449	             bypass the active-item guard"
450	        );
451	    }
452	    if !quit_changed {
453	        eprintln!(
454	            "warning: Zellij's `Ctrl q` `Quit` binding was not found in the \
455	             expected form, so it could not be gated; quitting will bypass \
456	             the active-item guard"
457	        );
458	    }
459	    let body = format!(
460	        "// PANopt cockpit Zellij config - generated by `panopt up`, regenerated\n\
461	         // each run from your own Zellij config. Zellij's Ctrl-S (scroll mode)\n\
462	         // is remapped to Ctrl-Shift-S so a bare Ctrl-S reaches panes: the todo\n\
