fn ensure_mouse_mode_enabled_flips_explicit_off() {
    let out = ensure_mouse_mode_enabled("keybinds {}\nmouse_mode false\n");
    assert!(out.contains("mouse_mode true"));
    assert!(!out.contains("mouse_mode false"));
    // No duplicate line gets appended when we flipped an existing one.
    assert_eq!(out.matches("mouse_mode true").count(), 1);
}

#[test]
fn ensure_mouse_mode_enabled_appends_when_absent() {
    let out = ensure_mouse_mode_enabled("keybinds {}\n");
    assert!(out.ends_with("mouse_mode true\n"));
    assert_eq!(out.matches("mouse_mode true").count(), 1);
}

#[test]
fn ensure_mouse_mode_enabled_is_idempotent_when_already_on() {
    let base = "keybinds {}\nmouse_mode true\n";
